import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums & processing fee
  it.todo("quote with empty item list returns premium 5 (processing fee only)");
  it.todo("quote for a single plain sword returns premium 105 (100 base + 5 fee, no first-insurance because: actually first-insurance applies — corrected next test)");
  it.todo("quote for a single plain sword (newcomer, first insurance) returns 115 (100 + 10 first + 5 fee)");
  it.todo("quote for a single plain amulet (newcomer) returns 71 (60 + 6 first + 5 fee)");
  it.todo("quote for a single plain staff (newcomer) returns 93 (80 + 8 first + 5 fee)");
  it.todo("quote for a single plain potion (newcomer) returns 49 (40 + 4 first + 5 fee)");

  // Components & blocks
  it.todo("quote for 1 rune (newcomer) returns ceil(25 + 2.5) + 5 = 33");
  it.todo("quote for 2 runes (newcomer) returns ceil(50 + 5) + 5 = 60");
  it.todo("quote for 3 runes (block, newcomer) returns ceil(60 + 6) + 5 = 71");
  it.todo("quote for 4 runes (newcomer, no block) returns ceil(100 + 10) + 5 = 115");
  it.todo("quote for 3 runes + 3 moonstones (newcomer, two blocks) returns ceil(120 + 12) + 5 = 137");
  it.todo("quote for 2 runes + 1 moonstone (newcomer, no block) returns ceil(75 + 7.5) + 5 = 88");

  // Item-level modifiers
  it.todo("quote for a cursed sword (newcomer) adds 50% surcharge on the cursed item");
  it.todo("quote for a highly-enchanted sword (level 5, newcomer) adds 30% surcharge");
  it.todo("quote for a cursed sword at enchantment exactly 5 (newcomer) applies both surcharges");

  // Policy-level modifiers
  it.todo("quote with loyalty (2+ years, newcomer-style otherwise) applies 20% discount on policy base");
  it.todo("quote for a follow-up contract (second quote) applies 15% discount on policy base");

  // Multi-item interaction
  it.todo("quote for a cursed sword + plain amulet applies curse surcharge to cursed item only");

  // Rounding (premium rounds up)
  it.todo("premium calculation that yields a fractional total rounds up to whole G");

  // Integration examples
  it.todo("newcomer with cursed sword (enchantment 3): premium is 165");
  it.todo("long-standing customer's second quote with cursed sword (enchantment 7): premium is 160");

  // Claims — basic
  it.todo("claim with no special clauses: damage minus 100 deductible");
  it.todo("claim with dragon material: full damage minus 100 deductible");
  it.todo("claim with enchantment >= 8: 50% damage minus 100 deductible");
  it.todo("claim with both clauses (dragon + ench>=8): 50% rule wins, then deductible");
  it.todo("claim damaging two insured items applies deductible per damage entry");
  it.todo("claim payout rounds down");
  it.todo("claim cap = 2x insurance sum; successive claims exhaust cap and remainingCap reaches 0");

  // Errors (basics)
  it.todo("quote with unknown item type causes CLI to exit non-zero with stderr error");
  it.todo("claim damage references item not in policy causes non-zero exit");
  it.todo("claim damage with negative amount causes non-zero exit");
  it.todo("claim damage entries exceed insured count of that type causes non-zero exit");
});

