describe("MHPCO Claim Office", () => {
  // Quote: base premiums & processing fee
  it("quote with empty item list returns premium 5 (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword (newcomer, first insurance) returns 115", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("quote for a single plain amulet (newcomer) returns 71 (60 + 6 first + 5 fee)");
  it.todo("quote for a single plain staff (newcomer) returns 93 (80 + 8 first + 5 fee)");
  it.todo("quote for a single plain potion (newcomer) returns 49 (40 + 4 first + 5 fee)");

  // Components & blocks
  it.todo("quote for 1 rune (newcomer) returns 33 (25 + 2.5 + 5, rounded up)");
  it.todo("quote for 2 runes (newcomer) returns 60 (50 + 5 + 5)");
  it.todo("quote for 3 runes block (newcomer) returns 71 (60 + 6 + 5)");
  it.todo("quote for 4 runes (newcomer, no block) returns 115 (100 + 10 + 5)");
  it.todo("quote for 2 runes + 1 moonstone (newcomer, no block) returns 88 (75 + 7.5 + 5, rounded up)");
  it.todo("quote for 3 runes + 3 moonstones (newcomer, two blocks) returns 137 (120 + 12 + 5)");

  // Item-level modifiers
  it.todo("quote for cursed sword (newcomer, enchantment 3) returns 165 (integration example)");
  it.todo("quote for sword at enchantment exactly 5 (newcomer) applies 30% high-enchantment surcharge");

  // Policy-level modifiers
  it.todo("quote with loyalty (2+ years) applies 20% discount on policy base");
  it.todo("quote for a follow-up contract (second quote) applies 15% discount on policy base");
  it.todo("long-standing customer's second quote with cursed sword (enchantment 7) returns 160 (integration example)");

  // Multi-item modifier scope
  it.todo("quote for cursed sword + plain amulet: curse surcharge applies to cursed item only (210 G before fee/first-insurance)");

  // Claims — basic
  it.todo("claim with no special clauses: regular sword damage 500 → payout 400 (full minus deductible)");
  it.todo("claim with dragon material: full damage minus deductible");
  it.todo("claim with enchantment >= 8: 50% of damage minus deductible");
  it.todo("claim with both dragon material and enchantment >= 9: 50% rule wins, then deductible");
  it.todo("claim with multiple damaged items: deductible applies per damage entry");
  it.todo("claim payout rounds down");
  it.todo("claim cap = 2x insurance sum; successive claims reduce remainingCap to 0");

  // Errors
  it.todo("quote with unknown item type causes CLI non-zero exit and stderr error");
  it.todo("claim damage references item not in policy causes non-zero exit");
  it.todo("claim damage with negative amount causes non-zero exit");
  it.todo("claim damage entries exceed insured count of that type causes non-zero exit");
});

