const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremiumFor = (items: { type: string }[]): number =>
  items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];

const quotePremium = (base: number): number =>
  Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);

export const runScenario = (scenario: any): unknown => {
  const base = basePremiumFor(scenario.steps[0].items);
  return { results: [{ premium: quotePremium(base) }] };
};

